1	//! `panopt _mcp-proxy` - a long-lived stdio MCP server that fronts panoptd.
2	//!
3	//! Claude Code spawns this at session start via `--mcp-config` type=stdio.
4	//! The proxy speaks MCP-over-stdio to Claude Code and MCP-over-HTTP to
5	//! panoptd, owning the panoptd session-id and reconnecting transparently
6	//! across daemon restarts. From Claude Code's point of view, panoptd never
7	//! goes away: a `just refresh` only stalls the next tool call for the time
8	//! it takes the new daemon to come up.
9	//!
10	//! Two transports, two MCP sessions:
11	//!
12	//! - The stdio side is a tiny MCP server. The proxy answers `initialize` and
13	//!   `notifications/initialized` itself (so Claude Code sees a stable
14	//!   server), and forwards everything else - `tools/list`, `tools/call`,
15	//!   future methods - to panoptd verbatim. The JSON-RPC `id` is preserved
16	//!   so the response correlates on Claude Code's side without rewrite.
17	//! - The HTTP side is the panoptd Streamable HTTP endpoint, scoped to this
18	//!   agent by `?ws=&agent=&name=&token=` baked into the URL. The proxy
19	//!   maintains its own `mcp-session-id` here. When a forwarded request
20	//!   fails (the daemon was killed, returned 4xx for an unknown session,
21	//!   refused the TCP connection), the proxy drops the session-id, re-runs
22	//!   `initialize` + `notifications/initialized`, and replays the original
23	//!   request - all invisible to Claude Code.
24	//!
25	//! Outage policy: hybrid. Each forwarded call retries against panoptd with
26	//! exponential backoff for up to [`RECONNECT_BUDGET`]. Short outages (a
27	//! `just refresh`, a brief daemon hiccup) look like a slow tool call to
28	//! Claude Code, no error. Longer outages fail with a JSON-RPC error so the
29	//! Claude Code conversation surface gets a visible failure rather than
30	//! hanging indefinitely.
31	
32	use std::io::{stdin, stdout, BufRead, BufReader, Write};
33	use std::path::{Path, PathBuf};
34	use std::thread;
35	use std::time::{Duration, Instant};
36	
37	use anyhow::{anyhow, bail, Context, Result};
38	use percent_encoding::{utf8_percent_encode, NON_ALPHANUMERIC};
39	use serde_json::{json, Value};
40	
41	/// The MCP protocol version the proxy advertises to Claude Code, and the
42	/// version it uses in its own `initialize` against panoptd. Kept aligned
43	/// with `mcpclient.rs` so the two sides speak the same protocol revision.
44	const PROTOCOL_VERSION: &str = "2025-06-18";
45	
46	/// How long a single forwarded request keeps retrying against panoptd
47	/// before giving up and returning a JSON-RPC error to Claude Code. Long
48	/// enough to cover a full `cargo build && cargo run` rebuild cycle, short
49	/// enough that a genuinely-dead daemon does not hang the conversation.
50	const RECONNECT_BUDGET: Duration = Duration::from_secs(30);
51	
52	/// Initial delay between reconnect attempts. Doubles up to
53	/// [`RECONNECT_BACKOFF_MAX`] so we hammer the daemon during the brief
54	/// shutdown-to-startup window without busy-spinning if it stays down.
55	const RECONNECT_BACKOFF_INITIAL: Duration = Duration::from_millis(200);
56	
57	/// Upper bound on the reconnect interval.
58	const RECONNECT_BACKOFF_MAX: Duration = Duration::from_secs(2);
59	
60	/// `panopt _mcp-proxy` entry point. Blocks until stdin closes (Claude Code
61	/// has gone away).
62	pub fn run(
63	    host: String,
64	    port: u16,
65	    ws: PathBuf,
66	    id: String,
67	    name: String,
68	    token: String,
69	) -> Result<()> {
70	    let url = build_url(&host, port, &ws, &id, &name, &token);
71	    let mut backend = Backend::new(url, id, name);
72	
73	    // Eagerly bring up the panoptd session so the agent registers in the
74	    // roster before its first tool call. Failure here is non-fatal: the
75	    // next forwarded request will retry the same connection sequence, so a
76	    // daemon that boots a little later still picks the agent up.
77	    if let Err(e) = backend.connect() {
78	        eprintln!("panopt-proxy: initial panoptd connect failed (will retry on first call): {e:#}");
79	    }
80	
81	    let stdin = stdin();
82	    let mut stdout = stdout().lock();
83	    let mut reader = BufReader::new(stdin.lock());
84	    let mut line = String::new();
85	
86	    loop {
87	        line.clear();
88	        let n = reader.read_line(&mut line).context("reading stdin")?;
89	        if n == 0 {
90	            break; // Claude Code closed stdin - session over.
91	        }
92	        let trimmed = line.trim();
93	        if trimmed.is_empty() {
94	            continue;
95	        }
96	        let req: Value = match serde_json::from_str(trimmed) {
97	            Ok(v) => v,
98	            Err(e) => {
99	                eprintln!("panopt-proxy: malformed JSON-RPC frame ignored: {e}");
100	                continue;
101	            }
102	        };
103	        if let Some(resp) = dispatch(&mut backend, &req) {
104	            let serialized = serde_json::to_string(&resp).expect("response must serialize as JSON");
105	            writeln!(stdout, "{serialized}").context("writing to stdout")?;
106	            stdout.flush().context("flushing stdout")?;
107	        }
108	    }
109	
110	    backend.farewell();
111	    Ok(())
112	}
113	
114	fn build_url(host: &str, port: u16, ws: &Path, id: &str, name: &str, token: &str) -> String {
115	    let encode = |s: &str| utf8_percent_encode(s, NON_ALPHANUMERIC).to_string();
116	    format!(
117	        "http://{host}:{port}/mcp?ws={}&agent={}&name={}&token={}",
118	        encode(&ws.to_string_lossy()),
119	        encode(id),
120	        encode(name),
121	        encode(token),
122	    )
123	}
124	
125	/// Route a JSON-RPC request: answer the lifecycle methods locally, forward
126	/// everything else to panoptd. Returns `Some(response)` for requests
127	/// (those carrying an `id`) and `None` for notifications.
128	fn dispatch(backend: &mut Backend, req: &Value) -> Option<Value> {
129	    let method = req.get("method").and_then(Value::as_str)?;
130	    let id = req.get("id").cloned();
131	    match method {
132	        "initialize" => Some(handle_initialize(backend, id)),
133	        "notifications/initialized" => None,
134	        _ => Some(forward_or_error(backend, req, id)),
135	    }
136	}
137	
138	/// Respond to Claude Code's `initialize` without forwarding. The proxy is
139	/// its own MCP server from Claude Code's perspective; the panoptd session
140	/// is independent and was (or will be) initialized via [`Backend::connect`].
141	fn handle_initialize(_backend: &mut Backend, id: Option<Value>) -> Value {
142	    json!({
143	        "jsonrpc": "2.0",
144	        "id": id,
145	        "result": {
146	            "protocolVersion": PROTOCOL_VERSION,
147	            "capabilities": { "tools": {} },
148	            "serverInfo": {
149	                "name": "panopt-proxy",
150	                "version": env!("CARGO_PKG_VERSION"),
151	            },
152	        },
153	    })
154	}
155	
156	/// Forward `req` to panoptd. On unrecoverable failure (the
157	/// [`RECONNECT_BUDGET`] elapsed), return a JSON-RPC error response so
158	/// Claude Code surfaces the outage instead of hanging.
159	fn forward_or_error(backend: &mut Backend, req: &Value, id: Option<Value>) -> Value {
160	    let body = req.to_string();
161	    match backend.forward(&body) {
162	        Ok(v) => v,
163	        Err(e) => json!({
164	            "jsonrpc": "2.0",
165	            "id": id,
166	            "error": {
167	                "code": -32603,
168	                "message": format!("panoptd unreachable: {e:#}"),
169	            },
170	        }),
171	    }
172	}
173	
174	/// Owns the panoptd MCP session. Reconnects transparently when the
175	/// daemon's session table forgets us (a restart, an idle reap).
176	struct Backend {
177	    url: String,
178	    /// Stable agent id used to call `agent_leave` at shutdown. Matches the
179	    /// `?agent=` parameter baked into [`Self::url`]; carried as a field so
180	    /// the proxy doesn't have to re-parse its own URL.
181	    agent_id: String,
182	    /// Friendly display name, baked into [`Self::url`] for the daemon's
183	    /// implicit identify on first sight. Held for symmetry with `agent_id`;
184	    /// not used after the URL is built.
185	    #[allow(dead_code)]
186	    name: String,
187	    /// Panoptd's `mcp-session-id` header value. `None` before the first
188	    /// successful `initialize`, or after a forwarded call discovered the
189	    /// session was forgotten.
190	    session_id: Option<String>,
191	}
192	
193	impl Backend {
194	    fn new(url: String, agent_id: String, name: String) -> Self {
195	        Backend {
196	            url,
197	            agent_id,
198	            name,
199	            session_id: None,
200	        }
201	    }
202	
203	    /// Initialize a fresh panoptd session: `initialize` request, capture
204	    /// the assigned `mcp-session-id`, send the `notifications/initialized`
205	    /// follow-up. Idempotent: a successful call replaces any prior session.
206	    fn connect(&mut self) -> Result<()> {
207	        let init_body = json!({
208	            "jsonrpc": "2.0",
209	            "id": 1,
210	            "method": "initialize",
211	            "params": {
212	                "protocolVersion": PROTOCOL_VERSION,
213	                "capabilities": {},
214	                "clientInfo": {
215	                    "name": "panopt-proxy",
216	                    "version": env!("CARGO_PKG_VERSION"),
217	                },
218	            },
219	        });
220	        let resp = ureq::post(&self.url)
221	            .set("Content-Type", "application/json")
222	            .set("Accept", "application/json, text/event-stream")
223	            .send_string(&init_body.to_string())
224	            .map_err(|e| anyhow!("initialize against panoptd: {e}"))?;
225	        let sid = resp
226	            .header("mcp-session-id")
227	            .map(str::to_string)
228	            .ok_or_else(|| anyhow!("panoptd returned no mcp-session-id on initialize"))?;
229	        let _ = resp.into_string(); // discard the JSON-RPC body; we only needed the header
230	
231	        let note = json!({ "jsonrpc": "2.0", "method": "notifications/initialized" });
232	        ureq::post(&self.url)
233	            .set("Content-Type", "application/json")
234	            .set("Accept", "application/json, text/event-stream")
235	            .set("mcp-session-id", &sid)
236	            .send_string(&note.to_string())
237	            .map_err(|e| anyhow!("initialized notification to panoptd: {e}"))?;
238	
239	        self.session_id = Some(sid);
240	        Ok(())
241	    }
242	
243	    /// POST `body` (a complete JSON-RPC frame) to panoptd with the current
244	    /// session id and return the parsed response. Re-establishes the
245	    /// session on failure and retries up to [`RECONNECT_BUDGET`].
246	    fn forward(&mut self, body: &str) -> Result<Value> {
247	        let deadline = Instant::now() + RECONNECT_BUDGET;
248	        let mut backoff = RECONNECT_BACKOFF_INITIAL;
249	        let mut last_err: Option<anyhow::Error> = None;
250	
251	        loop {
252	            if Instant::now() >= deadline {
253	                return Err(last_err.unwrap_or_else(|| anyhow!("reconnect budget exhausted")));
254	            }
255	            if self.session_id.is_none() {
256	                if let Err(e) = self.connect() {
257	                    last_err = Some(e);
258	                    thread::sleep(backoff);
259	                    backoff = (backoff * 2).min(RECONNECT_BACKOFF_MAX);
260	                    continue;
261	                }
262	            }
263	            match self.try_forward(body) {
264	                Ok(v) => return Ok(v),
265	                Err(e) => {
266	                    last_err = Some(e);
267	                    // The session id is either invalid (daemon restarted)
268	                    // or the daemon is unreachable - drop it and let the
269	                    // next iteration re-initialize. Sleeping keeps us from
270	                    // hammering a daemon that is mid-restart.
271	                    self.session_id = None;
272	                    thread::sleep(backoff);
273	                    backoff = (backoff * 2).min(RECONNECT_BACKOFF_MAX);
274	                }
275	            }
276	        }
277	    }
278	
279	    fn try_forward(&self, body: &str) -> Result<Value> {
280	        let sid = self
281	            .session_id
282	            .as_ref()
283	            .ok_or_else(|| anyhow!("no panoptd session"))?;
284	        let resp = ureq::post(&self.url)
285	            .set("Content-Type", "application/json")
286	            .set("Accept", "application/json, text/event-stream")
287	            .set("mcp-session-id", sid)
288	            .send_string(body)
289	            .map_err(|e| anyhow!("forwarding to panoptd: {e}"))?;
290	        let body = resp
291	            .into_string()
292	            .context("reading panoptd response body")?;
293	        parse_response(&body)
294	    }
295	
296	    /// On shutdown, best-effort: tell the daemon we are leaving so the
297	    /// registry entry and any held locks clear immediately, then close the
298	    /// HTTP session. Errors are swallowed - the agent is exiting anyway,
299	    /// and the next sweep will eventually catch the entry if this call
300	    /// failed to land.
301	    fn farewell(&mut self) {
302	        if self.session_id.is_none() {
303	            return;
304	        }
305	        let req = json!({
306	            "jsonrpc": "2.0",
307	            "id": 99,
308	            "method": "tools/call",
309	            "params": { "name": "agent_leave", "arguments": {} },
310	        });
311	        let _ = self.try_forward(&req.to_string());
312	        if let Some(sid) = self.session_id.take() {
313	            let _ = ureq::delete(&self.url).set("mcp-session-id", &sid).call();
314	        }
315	        let _ = &self.agent_id; // silence unused-field warning if logging is added later
316	    }
317	}
318	
319	/// Parse a Streamable HTTP response body: either a bare JSON object or a
320	/// `text/event-stream` body whose `data:` lines concatenate into the
321	/// JSON-RPC frame. Mirrors the same logic in `mcpclient.rs` so behavior is
322	/// identical across the CLI's one-shot calls and the proxy's forwards.
323	fn parse_response(body: &str) -> Result<Value> {
324	    let trimmed = body.trim_start();
325	    if trimmed.starts_with('{') {
326	        return serde_json::from_str(trimmed).context("parsing JSON response");
327	    }
328	    let mut data = String::new();
329	    for line in body.lines() {
330	        if let Some(rest) = line.strip_prefix("data:") {
331	            data.push_str(rest.strip_prefix(' ').unwrap_or(rest));
332	        }
333	    }
334	    if data.is_empty() {
335	        bail!("empty response from panoptd");
336	    }
337	    serde_json::from_str(&data).context("parsing SSE data payload")
338	}
339	
340	#[cfg(test)]
341	mod tests {
342	    use super::*;
343	
344	    #[test]
345	    fn parse_response_reads_a_plain_body() {
346	        let v = parse_response(r#"{"jsonrpc":"2.0","id":1,"result":{"ok":true}}"#).unwrap();
347	        assert_eq!(v["result"]["ok"], json!(true));
348	    }
349	
350	    #[test]
351	    fn parse_response_reads_an_sse_body() {
352	        let body = "event: message\ndata: {\"jsonrpc\":\"2.0\",\"id\":1,\"result\":42}\n\n";
353	        assert_eq!(parse_response(body).unwrap()["result"], json!(42));
354	    }
355	
356	    #[test]
357	    fn build_url_percent_encodes_every_field() {
358	        let url = build_url(
359	            "127.0.0.1",
360	            7600,
361	            Path::new("/tmp/with spaces"),
362	            "user-host",
363	            "Display Name",
364	            "tok/en+with=stuff",
365	        );
366	        // Slashes, spaces, and special URL characters must be escaped so a
367	        // malformed query string cannot break the request.
368	        assert!(url.contains("ws=%2Ftmp%2Fwith%20spaces"), "{url}");
369	        assert!(url.contains("name=Display%20Name"), "{url}");
370	        assert!(url.contains("token=tok%2Fen%2Bwith%3Dstuff"), "{url}");
371	    }
372	
373	    #[test]
374	    fn dispatch_answers_initialize_locally() {
375	        let mut backend = Backend::new(
376	            "http://127.0.0.1:0/mcp".into(),
377	            "alpha".into(),
378	            "alpha".into(),
379	        );
380	        let req = json!({"jsonrpc": "2.0", "id": 7, "method": "initialize"});
381	        let resp = dispatch(&mut backend, &req).unwrap();
382	        assert_eq!(resp["id"], json!(7));
383	        assert_eq!(resp["result"]["serverInfo"]["name"], "panopt-proxy");
384	        // We did not connect to panoptd, so the session must still be empty.
385	        assert!(backend.session_id.is_none());
386	    }
387	
388	    #[test]
389	    fn dispatch_ignores_initialized_notification() {
390	        let mut backend = Backend::new(
391	            "http://127.0.0.1:0/mcp".into(),
392	            "alpha".into(),
393	            "alpha".into(),
394	        );
395	        let req = json!({"jsonrpc": "2.0", "method": "notifications/initialized"});
396	        assert!(dispatch(&mut backend, &req).is_none());
397	    }
398	}
