8	/// Check if a type is Json<T> and extract the inner type T
9	fn extract_json_inner_type(ty: &syn::Type) -> Option<&syn::Type> {
10	    if let syn::Type::Path(type_path) = ty {
11	        if let Some(last_segment) = type_path.path.segments.last() {
12	            if last_segment.ident == "Json" {
13	                if let syn::PathArguments::AngleBracketed(args) = &last_segment.arguments {
14	                    if let Some(syn::GenericArgument::Type(inner_type)) = args.args.first() {
15	                        return Some(inner_type);
16	                    }
17	                }
18	            }
19	        }
20	    }
21	    None
22	}
23	
24	/// Extract schema expression from a function's return type
25	/// Handles patterns like Json<T> and Result<Json<T>, E>
26	fn extract_schema_from_return_type(ret_type: &syn::Type) -> Option<Expr> {
27	    // First, try direct Json<T>
28	    if let Some(inner_type) = extract_json_inner_type(ret_type) {
29	        return syn::parse2::<Expr>(quote! {
30	            rmcp::handler::server::tool::schema_for_output::<#inner_type>()
31	                .unwrap_or_else(|e| {
32	                    panic!(
33	                        "Invalid output schema for Json<{}>: {}",
34	                        std::any::type_name::<#inner_type>(),
35	                        e
36	                    )
37	                })
38	        })
39	        .ok();
40	    }
41	
42	    // Then, try Result<Json<T>, E>
43	    let type_path = match ret_type {
44	        syn::Type::Path(path) => path,
45	        _ => return None,
46	    };
47	
48	    let last_segment = type_path.path.segments.last()?;
49	
50	    if last_segment.ident != "Result" {
51	        return None;
52	    }
53	
54	    let args = match &last_segment.arguments {
55	        syn::PathArguments::AngleBracketed(args) => args,
56	        _ => return None,
57	    };
58	
59	    let ok_type = match args.args.first()? {
60	        syn::GenericArgument::Type(ty) => ty,
61	        _ => return None,
62	    };
63	
64	    let inner_type = extract_json_inner_type(ok_type)?;
65	
66	    syn::parse2::<Expr>(quote! {
67	        rmcp::handler::server::tool::schema_for_output::<#inner_type>()
68	            .unwrap_or_else(|e| {
69	                panic!(
70	                    "Invalid output schema for Result<Json<{}>, E>: {}",
71	                    std::any::type_name::<#inner_type>(),
72	                    e
73	                )
74	            })
75	    })
76	    .ok()
77	}
78	#[derive(FromMeta, Default, Debug)]
79	#[darling(default)]
80	pub struct ToolAttribute {
81	    /// The name of the tool
82	    pub name: Option<String>,
83	    /// Human readable title of tool
84	    pub title: Option<String>,
85	    pub description: Option<String>,
86	    /// A JSON Schema object defining the expected parameters for the tool
87	    pub input_schema: Option<Expr>,
88	    /// An optional JSON Schema object defining the structure of the tool's output
89	    pub output_schema: Option<Expr>,
90	    /// Optional additional tool information.
91	    pub annotations: Option<ToolAnnotationsAttribute>,
92	    /// Execution-related configuration including task support.
93	    pub execution: Option<ToolExecutionAttribute>,
94	    /// Optional icons for the tool
95	    pub icons: Option<Expr>,
96	    /// Optional metadata for the tool
