217	        Default::default()
218	    } else {
219	        let attr_args = NestedMeta::parse_meta_list(attr)?;
220	        ToolAttribute::from_list(&attr_args)?
221	    };
222	    let mut fn_item = syn::parse2::<ImplItemFn>(input.clone())?;
223	    let fn_ident = &fn_item.sig.ident;
224	
225	    let tool_attr_fn_ident = format_ident!("{}_tool_attr", fn_ident);
226	    let input_schema_expr = if let Some(input_schema) = attribute.input_schema {
227	        input_schema
228	    } else {
229	        // try to find some parameters wrapper in the function
230	        let params_ty = crate::common::find_parameters_type_impl(&fn_item);
231	        if let Some(params_ty) = params_ty {
232	            // if found, use the Parameters schema
233	            syn::parse2::<Expr>(quote! {
234	                rmcp::handler::server::common::schema_for_type::<#params_ty>()
235	            })?
236	        } else {
237	            // if not found, use a default empty JSON schema object
238	            // TODO: should be updated according to the new specifications
239	            syn::parse2::<Expr>(quote! {
240	                rmcp::handler::server::common::schema_for_empty_input()
241	            })?
242	        }
243	    };
244	    let annotations_expr = if let Some(annotations) = attribute.annotations {
245	        let ToolAnnotationsAttribute {
246	            title,
247	            read_only_hint,
248	            destructive_hint,
249	            idempotent_hint,
250	            open_world_hint,
251	        } = annotations;
252	        fn wrap_option<T: ToTokens>(x: Option<T>) -> TokenStream {
253	            x.map(|x| quote! {Some(#x.into())})
254	                .unwrap_or(quote! { None })
255	        }
256	        let title = wrap_option(title);
257	        let read_only_hint = wrap_option(read_only_hint);
258	        let destructive_hint = wrap_option(destructive_hint);
259	        let idempotent_hint = wrap_option(idempotent_hint);
260	        let open_world_hint = wrap_option(open_world_hint);
261	        let token_stream = quote! {
262	            rmcp::model::ToolAnnotations::from_raw(
263	                #title,
264	                #read_only_hint,
265	                #destructive_hint,
266	                #idempotent_hint,
267	                #open_world_hint,
268	            )
269	        };
270	        Some(syn::parse2::<Expr>(token_stream)?)
271	    } else {
272	        None
273	    };
274	    let execution_expr = if let Some(execution) = attribute.execution {
275	        let ToolExecutionAttribute { task_support } = execution;
276	
277	        let task_support_expr = if let Some(ts) = task_support {
278	            let ts_ident = match ts.as_str() {
279	                "forbidden" => quote! { rmcp::model::TaskSupport::Forbidden },
280	                "optional" => quote! { rmcp::model::TaskSupport::Optional },
281	                "required" => quote! { rmcp::model::TaskSupport::Required },
282	                _ => {
283	                    return Err(syn::Error::new(
284	                        Span::call_site(),
285	                        format!(
286	                            "Invalid task_support value '{}'. Expected 'forbidden', 'optional', or 'required'",
287	                            ts
288	                        ),
289	                    ));
290	                }
291	            };
292	            quote! { Some(#ts_ident) }
293	        } else {
294	            quote! { None }
295	        };
296	
297	        let token_stream = quote! {
298	            rmcp::model::ToolExecution::from_raw(
299	                #task_support_expr,
300	            )
301	        };
302	        Some(syn::parse2::<Expr>(token_stream)?)
303	    } else {
304	        None
305	    };
306	    // Handle output_schema - either explicit or generated from return type
307	    let output_schema_expr = attribute.output_schema.or_else(|| {
308	        // Try to generate schema from return type
309	        match &fn_item.sig.output {
310	            syn::ReturnType::Type(_, ret_type) => extract_schema_from_return_type(ret_type),
311	            _ => None,
312	        }
313	    });
314	
315	    let description_expr = if let Some(s) = attribute.description {
316	        Some(Expr::Lit(syn::ExprLit {
317	            attrs: Vec::new(),
318	            lit: syn::Lit::Str(LitStr::new(&s, Span::call_site())),
319	        }))
320	    } else {
321	        fn_item.attrs.iter().try_fold(None, extract_doc_line)?
322	    };
323	    let resolved_tool_attr = ResolvedToolAttribute {
324	        name: attribute.name.unwrap_or_else(|| fn_ident.to_string()),
325	        description: description_expr,
326	        input_schema: input_schema_expr,
327	        output_schema: output_schema_expr,
328	        annotations: annotations_expr,
329	        execution: execution_expr,
330	        title: attribute.title,
331	        icons: attribute.icons,
332	        meta: attribute.meta,
333	    };
334	    let tool_attr_fn = resolved_tool_attr.into_fn(tool_attr_fn_ident)?;
335	    // modify the the input function
336	    if fn_item.sig.asyncness.is_some() {
337	        // 1. remove asyncness from sig
338	        // 2. make return type: `std::pin::Pin<Box<dyn std::future::Future<Output = #ReturnType> + Send + '_>>`
339	        //    (omit `+ Send` when the `local` crate feature is active or `#[tool(local)]` is used)
340	        // 3. make body: { Box::pin(async move { #body }) }
341	        let omit_send = cfg!(feature = "local") || attribute.local;
342	        let new_output = syn::parse2::<ReturnType>({
343	            let mut lt = quote! { 'static };
344	            if let Some(receiver) = fn_item.sig.receiver() {
345	                if let Some((_, receiver_lt)) = receiver.reference.as_ref() {
346	                    if let Some(receiver_lt) = receiver_lt {
347	                        lt = quote! { #receiver_lt };
348	                    } else {
349	                        lt = quote! { '_ };
350	                    }
351	                }
352	            }
353	            match &fn_item.sig.output {
354	                syn::ReturnType::Default => {
355	                    if omit_send {
356	                        quote! { -> ::std::pin::Pin<Box<dyn ::std::future::Future<Output = ()> + #lt>> }
357	                    } else {
358	                        quote! { -> ::std::pin::Pin<Box<dyn ::std::future::Future<Output = ()> + Send + #lt>> }
359	                    }
360	                }
361	                syn::ReturnType::Type(_, ty) => {
362	                    if omit_send {
363	                        quote! { -> ::std::pin::Pin<Box<dyn ::std::future::Future<Output = #ty> + #lt>> }
364	                    } else {
365	                        quote! { -> ::std::pin::Pin<Box<dyn ::std::future::Future<Output = #ty> + Send + #lt>> }
366	                    }
367	                }
368	            }
369	        })?;
370	        let prev_block = &fn_item.block;
371	        let new_block = syn::parse2::<syn::Block>(quote! {
372	           { Box::pin(async move #prev_block ) }
373	        })?;
374	        fn_item.sig.asyncness = None;
375	        fn_item.sig.output = new_output;
376	        fn_item.block = new_block;
377	    }
378	    Ok(quote! {
379	        #tool_attr_fn
380	        #fn_item
381	    })
382	}
