327	/// as an [`IdKindDto`].
328	///
329	/// Per-table `NotFound` is treated as "miss, try next"; any other `CoreError`
330	/// (DB, projection, project-not-found) short-circuits as a real failure. If
331	/// no table matches, emits `invalid_params` with a generic "id N not found"
332	/// (the caller doesn't have a kind to attribute the miss to). Soft-deleted
333	/// rows are already invisible to the underlying `*_get` helpers (V7), so
334	/// they look the same as ids that were never allocated.
335	fn resolve_id_kind(store: &Store, project: ProjectId, id: u64) -> Result<IdKindDto, McpError> {
336	    match store.todo_get(project, id) {
337	        Ok(t) => {
338	            return Ok(IdKindDto {
339	                kind: "todo",
340	                label: t.title,
341	            })
342	        }
343	        Err(CoreError::TodoNotFound(_)) => {}
344	        Err(e) => return Err(map_core_err(e)),
345	    }
346	    match store.scratchpad_get(project, id) {
347	        Ok(s) => {
348	            return Ok(IdKindDto {
349	                kind: "scratchpad",
350	                label: s.title,
351	            })
352	        }
