354	        Err(e) => return Err(map_core_err(e)),
355	    }
356	    match store.agent_tool_get(project, id) {
357	        Ok(at) => {
358	            let label = if at.display_name.is_empty() {
359	                at.name
360	            } else {
361	                at.display_name
362	            };
363	            return Ok(IdKindDto {
364	                kind: "agent-tool",
365	                label,
366	            });
367	        }
368	        Err(CoreError::AgentToolNotFound(_)) => {}
369	        Err(e) => return Err(map_core_err(e)),
370	    }
371	    match store.process_get(project, id) {
372	        Ok(p) => {
373	            let label = if p.display_name.is_empty() {
374	                p.name
375	            } else {
376	                p.display_name
377	            };
378	            return Ok(IdKindDto {
379	                kind: "process",
380	                label,
381	            });
382	        }
383	        Err(CoreError::ProcessNotFound(_)) => {}
384	        Err(e) => return Err(map_core_err(e)),
385	    }
386	    Err(McpError::invalid_params(
387	        format!("id {id} not found"),
388	        None,
