392	/// Map a core error onto an MCP error result at the protocol boundary.
393	fn map_core_err(e: CoreError) -> McpError {
394	    match e {
395	        // Caller-fixable: a bad id, a rejected argument, or a workspace path
396	        // the daemon cannot reach.
397	        CoreError::ScratchpadNotFound(_)
398	        | CoreError::TodoNotFound(_)
399	        | CoreError::TodoCommentNotFound { .. }
400	        | CoreError::AgentToolNotFound(_)
401	        | CoreError::ProcessNotFound(_)
402	        | CoreError::BadRequest(_)
403	        | CoreError::Workspace(_) => McpError::invalid_params(e.to_string(), None),
404	        // Internal: a stale project handle, a database fault, or a failed write.
405	        CoreError::ProjectNotFound(_) | CoreError::Db(_) | CoreError::Projection(_) => {
406	            McpError::internal_error(e.to_string(), None)
407	        }
408	    }
409	}
