411	/// Find `key`'s value in a URL query string, percent-decoded.
412	///
413	/// `query` is the raw query component, with no leading `?`, as returned by
414	/// [`http::Uri::query`].
415	fn query_param(query: Option<&str>, key: &str) -> Option<String> {
416	    let prefix = format!("{key}=");
417	    let raw = query?
418	        .split('&')
419	        .find_map(|kv| kv.strip_prefix(prefix.as_str()))?;
420	    Some(
421	        percent_encoding::percent_decode_str(raw)
422	            .decode_utf8_lossy()
423	            .into_owned(),
424	    )
425	}
