                        .and_then(|k| st.agent_whoami(project, k))
                        .map(|a| a.name)
                })
                .or(key)
                .unwrap_or_else(|| "unknown".to_string());
            st.todo_comment_add(project, args.todo_id, author, args.body)
                .map_err(map_core_err)?
