1	//! `panoptd` - the PANopt coordination daemon.
2	//!
3	//! Runs one MCP server over Streamable HTTP. Every connected agent shares one
4	//! SQLite-backed store; each connection is scoped to a project by the `ws`
5	//! query parameter on its MCP URL, and that project's state is mirrored to
6	//! `.panopt/*.md` under the project root.
7	//!
8	//! The bind address is configurable (`--host`) so the daemon can serve agents
9	//! on other machines, and every request must carry a bearer token - the same
10	//! one regardless of bind, so loopback and remote callers go through the
11	//! exact same gate.
12	
13	mod handler;
14	
15	use std::path::PathBuf;
16	use std::sync::{Arc, Mutex};
17	
18	use anyhow::Context;
19	use axum::{
20	    body::Body,
21	    extract::{Request, State},
22	    http::{header::AUTHORIZATION, StatusCode},
23	    middleware::{self, Next},
24	    response::Response,
25	};
26	use clap::Parser;
27	use panopt_core::Store;
28	use rmcp::transport::streamable_http_server::{
29	    session::local::LocalSessionManager, StreamableHttpServerConfig, StreamableHttpService,
30	};
31	
32	use crate::handler::Handler;
33	
34	#[derive(Parser)]
35	#[command(name = "panoptd", about = "PANopt coordination daemon")]
36	struct Cli {
37	    /// SQLite database file holding every project's state. Defaults to
38	    /// `panopt/panopt.db` under the per-user data directory.
39	    #[arg(long)]
40	    db: Option<PathBuf>,
41	
42	    /// Address to bind the MCP server to. Defaults to loopback; pass
43	    /// `0.0.0.0` (or a specific interface IP) to accept connections from
44	    /// other hosts. Bearer-token auth is always required regardless of host.
45	    #[arg(long, default_value = "127.0.0.1")]
46	    host: String,
47	
48	    /// TCP port for the MCP server.
49	    #[arg(long, default_value_t = 7600)]
50	    port: u16,
51	}
52	
53	/// The default database location: `<data-dir>/panopt/panopt.db`, where
54	/// `<data-dir>` is the platform's per-user data directory.
55	fn default_db_path() -> anyhow::Result<PathBuf> {
56	    let dir = dirs::data_dir()
57	        .context("could not locate a per-user data directory; pass --db explicitly")?;
58	    Ok(dir.join("panopt").join("panopt.db"))
59	}
60	
61	/// The token file path: `<data-dir>/panopt/token`. Daemon and launcher agree
62	/// on this so both can locate the shared bearer token without a flag.
63	fn default_token_path() -> anyhow::Result<PathBuf> {
64	    let dir = dirs::data_dir()
65	        .context("could not locate a per-user data directory; cannot place the token file")?;
66	    Ok(dir.join("panopt").join("token"))
67	}
68	
69	/// Bearer-token gate around every MCP request.
70	///
71	/// Accepts the token via `Authorization: Bearer <token>` (preferred) or via
72	/// a `?token=<token>` query parameter (a fallback for MCP clients that
73	/// cannot set custom headers). Always required, including on loopback - the
74	/// token file is 0600, so any process able to read it is already running as
75	/// the same user, and a uniform gate is simpler than per-host policy.
76	async fn require_token(
77	    State(token): State<Arc<String>>,
78	    req: Request<Body>,
79	    next: Next,
80	) -> Result<Response, StatusCode> {
81	    if has_valid_token(&req, &token) {
82	        Ok(next.run(req).await)
83	    } else {
84	        Err(StatusCode::UNAUTHORIZED)
85	    }
86	}
87	
88	fn has_valid_token(req: &Request<Body>, token: &str) -> bool {
89	    if let Some(h) = req
90	        .headers()
91	        .get(AUTHORIZATION)
92	        .and_then(|v| v.to_str().ok())
93	        .and_then(|s| s.strip_prefix("Bearer "))
94	    {
95	        if h.trim() == token {
96	            return true;
97	        }
98	    }
99	    let query = req.uri().query().unwrap_or("");
100	    for kv in query.split('&') {
101	        if let Some(v) = kv.strip_prefix("token=") {
102	            let decoded = percent_encoding::percent_decode_str(v).decode_utf8_lossy();
103	            if decoded == token {
104	                return true;
105	            }
106	        }
107	    }
108	    false
109	}
110	
111	#[tokio::main]
112	async fn main() -> anyhow::Result<()> {
113	    tracing_subscriber::fmt()
114	        .with_env_filter(
115	            tracing_subscriber::EnvFilter::try_from_default_env()
116	                .unwrap_or_else(|_| tracing_subscriber::EnvFilter::new("info")),
117	        )
118	        .init();
119	
120	    let cli = Cli::parse();
121	
122	    let db_path = match cli.db {
123	        Some(p) => p,
124	        None => default_db_path()?,
125	    };
126	    if let Some(parent) = db_path.parent() {
127	        std::fs::create_dir_all(parent)
128	            .with_context(|| format!("failed to create data directory {}", parent.display()))?;
129	    }
130	
131	    // One Store, wrapped once. The factory closure below clones this Arc per
132	    // MCP session; all clones point at this single Mutex<Store>.
133	    let shared = Arc::new(Mutex::new(
134	        Store::open(&db_path).context("failed to open the panopt database")?,
135	    ));
136	
137	    tracing::info!(db = %db_path.display(), "panoptd starting");
138	    tracing::info!(
139	        "MCP endpoint: http://{}:{}/mcp?ws=<project path>",
140	        cli.host,
141	        cli.port
142	    );
143	
144	    // Drop agents that have gone silent, every 30s, so a closed agent leaves
145	    // the registry even when no other agent is active to trigger a prune.
146	    let sweep_state = shared.clone();
147	    tokio::spawn(async move {
148	        let mut ticker = tokio::time::interval(std::time::Duration::from_secs(30));
149	        loop {
150	            ticker.tick().await;
151	            let swept = {
152	                let mut st = sweep_state.lock().expect("state mutex poisoned");
153	                st.sweep_idle_agents()
154	            };
155	            match swept {
156	                Ok(keys) => {
157	                    for key in keys {
158	                        tracing::info!(agent = %key, "agent left (idle)");
159	                    }
160	                }
161	                Err(e) => tracing::warn!("agent sweep failed: {e}"),
162	            }
163	        }
164	    });
165	
166	    let token_path = default_token_path()?;
167	    let token = panopt_core::auth::ensure_token(&token_path)
168	        .with_context(|| format!("ensuring panopt token at {}", token_path.display()))?;
169	    tracing::info!(token = %token_path.display(), "panopt token ready");
170	
171	    let factory_state = shared.clone();
172	    let service = StreamableHttpService::new(
173	        move || Ok(Handler::new(factory_state.clone())),
174	        LocalSessionManager::default().into(),
175	        StreamableHttpServerConfig::default(),
176	    );
177	
178	    let token_for_auth = Arc::new(token);
179	    let router =
180	        axum::Router::new()
181	            .nest_service("/mcp", service)
182	            .layer(middleware::from_fn_with_state(
183	                token_for_auth,
184	                require_token,
185	            ));
186	    let listener = tokio::net::TcpListener::bind((cli.host.as_str(), cli.port))
187	        .await
188	        .with_context(|| format!("failed to bind {}:{}", cli.host, cli.port))?;
189	
190	    let shutdown_state = shared.clone();
191	    axum::serve(listener, router)
192	        .with_graceful_shutdown(shutdown_when_safe(shutdown_state))
193	        .await
194	        .context("server error")?;
195	
196	    Ok(())
197	}
