    fn dispatch_answers_initialize_locally() {
        let mut backend = Backend::new(
            "http://127.0.0.1:0/mcp".into(),
            "alpha".into(),
            "alpha".into(),
        );
        let req = json!({"jsonrpc": "2.0", "id": 7, "method": "initialize"});
